    82|/**
    83| * Supabase session storage adapter.
    84| *
    85| * IMPORTANT: We use AsyncStorage (not SecureStore) because Supabase session
    86| * payloads (access_token + refresh_token + user JSON) routinely exceed 2KB,
    87| * which is above expo-secure-store's per-value limit on Android. When the
    88| * limit is hit, setItemAsync fails silently and the session is never persisted
    89| * — causing the user to be logged out every time the app is closed.
    90| *
    91| * AsyncStorage is the storage layer recommended by the official Supabase
    92| * Expo/React Native guide and supports payloads of any practical size.
    93| *
    94| * On web, AsyncStorage transparently uses localStorage. SecureStore is no-op
    95| * on web, so this adapter also fixes web persistence in Expo web builds.
    96| *
    97| * Migration: on first read, if the new AsyncStorage slot is empty but a
    98| * legacy SecureStore value exists for the same key, we copy it over so
    99| * users who were authenticated under the old setup remain logged in.
   100| */
   101|async function migrateLegacySecureStoreValue(key: string): Promise<string | null> {
   102|  if (Platform.OS === 'web') return null;
   103|  try {
   104|    const legacy = await SecureStore.getItemAsync(key);
   105|    if (!legacy) return null;
   106|    await AsyncStorage.setItem(key, legacy);
   107|    try { await SecureStore.deleteItemAsync(key); } catch {}
   108|    console.log('[Supabase] Migrated legacy SecureStore session to AsyncStorage for key:', key);
   109|    return legacy;
   110|  } catch {
   111|    return null;
   112|  }
